jQuery(document).ready(function($){$(window).scroll(function(){if($(window).width()<767){const toolsCertPos=$('.tools-certificates-section').offset().top-200;if($(window).scrollTop()>toolsCertPos){if(!$('.tools-certificates-section .doodle').hasClass('animate')){$('.tools-certificates-section .doodle').addClass('animate')}}}})});function openTab(evt,tabName){var i,tabContent,tabButtons;tabContent=document.getElementsByClassName("tab-pane");tabButtons=document.getElementsByClassName("advance-tab-btn");for(i=0;i<tabContent.length;i++){tabContent[i].classList.remove("active")}
for(i=0;i<tabButtons.length;i++){tabButtons[i].classList.remove("active")}
document.getElementById(tabName).classList.add("active");evt.currentTarget.classList.add("active")}
document.addEventListener("DOMContentLoaded",function(){const tab1=document.getElementById("tab1");if(tab1){document.getElementById("tab1").classList.add("active")}});document.addEventListener("DOMContentLoaded",function(){const accordions=document.querySelectorAll(".accordion");if(accordions.length>0){const firstAccordion=accordions[0];const firstButton=firstAccordion.querySelector(".accordion-btn");const firstPanel=firstAccordion.querySelector(".accordion-panel");if(firstButton&&firstPanel){firstButton.classList.add("active");firstPanel.style.display="block";firstButton.style.background="#F7F6F6"}}
document.querySelectorAll(".accordion-btn").forEach((button)=>{button.addEventListener("click",function(){let panel=this.nextElementSibling;if(!panel)return;let isActive=this.classList.contains("active");document.querySelectorAll(".accordion-btn").forEach((b)=>{b.classList.remove("active");b.style.background=""});document.querySelectorAll(".accordion-panel").forEach((p)=>{p.style.display="none"});if(!isActive){this.classList.add("active");this.style.background="#F6E6C5";panel.style.display="block"}})})});jQuery(document).ready(function($){$(document).on('click','.course-enhance-skills .tablinks',function(){var tabItem=$(this).data('tabitem');$(this).parents('.content').find('.tabcontent').removeClass('active');$(this).parents('.content').find('.tablinks').removeClass('active');$("#"+tabItem).addClass("active");$(this).addClass('active')});function toggleSubmitButton(){let goalSelected=$(".select-goal-field").val();let domainSelected=$(".select-domain-field").val();if(goalSelected&&domainSelected){$(".tools-cert-sumbit-btn").prop("disabled",!1);$(".tools-cert-sumbit-btn").removeClass("disabled-btn")}else{$(".tools-cert-sumbit-btn").addClass("disabled-btn");$(".tools-cert-sumbit-btn").prop("disabled",!0)}}
$(".select-goal-field, .select-domain-field").on("change",toggleSubmitButton);setTimeout(function(){$('.select-goal-field').val(null).trigger('change');$('.select-domain-field').val(null).trigger('change')},500)})